changeSet.sql:
ALTER TABLE product ADD CONSTRAINT chk_product_price_nonnegative CHECK (price >= 0), ADD CONSTRAINT chk_product_stock_nonnegative CHECK (stock_quantity >= 0);
ALTER TABLE media ADD CONSTRAINT chk_media_position_nonnegative CHECK (position >= 0), ADD CONSTRAINT uk_media_product_type_position UNIQUE (product_id, type, position), ADD CONSTRAINT chk_media_main_image_position CHECK (is_main = FALSE OR (type = 'IMAGE' AND position = 0));
ALTER TABLE cms_block ADD CONSTRAINT chk_cms_block_sort_order_nonnegative CHECK (sort_order >= 0), ADD CONSTRAINT uk_cms_block_page_sort_order UNIQUE (page_id, sort_order);

rollback.sql:
